# scripts/check_version_policy.py (sunset enforcement section)
from datetime import date

SUNSET_DATES = {
    "langchain": {
        "0.1": date(2026, 3, 1),   # hard sunset date for 0.1.x
    },
    "torch": {
        "2.1": date(2026, 1, 1),
    },
}

def check_sunset_violations(packages: dict) -> list[str]:
    today = date.today()
    violations = []
    for pkg, version in packages.items():
        minor = ".".join(version.split(".")[:2])
        if pkg in SUNSET_DATES and minor in SUNSET_DATES[pkg]:
            sunset = SUNSET_DATES[pkg][minor]
            if today >= sunset:
                violations.append(
                    f"{pkg}=={version} reached hard sunset on {sunset} "
                    f"({(today - sunset).days} days ago). "
                    f"Deployment blocked. Upgrade to approved version before redeploying."
                )
            elif (sunset - today).days <= 30:
                violations.append(
                    f"{pkg}=={version} hard sunset in {(sunset - today).days} days ({sunset}). "
                    f"Upgrade urgently."
                )
    return violations

