# Generates a progress report for a deprecation notice
import json, requests, os

INVENTORY_URL = os.environ["VERSION_INVENTORY_URL"]
WAIVER_URL    = os.environ["WAIVER_REGISTRY_URL"]

def migration_progress_report(package: str, deprecated_pattern: str) -> dict:
    # 1. Get all services that were affected at notice date
    affected = requests.get(
        f"{INVENTORY_URL}/affected",
        params={"package": package, "pattern": deprecated_pattern}
    ).json()

    # 2. Get current inventory to see who has already migrated
    current = requests.get(
        f"{INVENTORY_URL}/current",
        params={"package": package}
    ).json()

    still_on_deprecated = [
        s for s in affected
        if any(c["service"] == s and c["version_matches_pattern"] for c in current)
    ]

    # 3. Get active waivers
    waivers = requests.get(
        f"{WAIVER_URL}/active",
        params={"package": package}
    ).json()

    return {
        "package": package,
        "deprecated_pattern": deprecated_pattern,
        "total_affected": len(affected),
        "migrated": len(affected) - len(still_on_deprecated),
        "still_on_deprecated": len(still_on_deprecated),
        "migration_pct": round((len(affected) - len(still_on_deprecated)) / len(affected) * 100),
        "active_waivers": len(waivers),
        "at_risk_services": [s for s in still_on_deprecated if s not in [w["service"] for w in waivers]],
    }

if __name__ == "__main__":
    report = migration_progress_report("langchain", r"^0\.1\.")
    print(json.dumps(report, indent=2))
    if report["at_risk_services"]:
        print(f"\nAT RISK (no waiver, not migrated): {report['at_risk_services']}")
